import '../../models/character.dart';
import '../../models/game_theme.dart';

GameCharacter bs(String file, String ruName, [List<String> aliases = const []]) {
  return GameCharacter(
    id: file.toLowerCase(),
    name: ruName,
    theme: GameTheme.brawlStars,
    imageAsset: 'assets/characters/brawl_stars/$file.png',
    aliases: aliases,
  );
}

